<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Models\Payroll\PayrollItem; use App\Services\Foundation\SchoolProfileService; use Illuminate\View\View; class EmployeePayslipController extends Controller{public function index():View{$employee=auth()->user()->employee; return view('payroll.payslips.mine',['title'=>'Slip Gaji Saya','items'=>$employee?PayrollItem::where('employee_id',$employee->id)->with('run.period')->latest()->paginate(12):collect()]);} public function show(PayrollItem $item,SchoolProfileService $profiles):View{abort_unless(auth()->user()->employee?->id===$item->employee_id,403); return view('payroll.payslips.show',['title'=>'Slip Gaji Saya','item'=>$item->load('run.period','components','payments'),'profile'=>$profiles->current()]);}}
